sourcesContent:
import styled from "styled-components";

export const Container = styled.div`
    width: 100%;
    height: 90%;
`;

export const Label = styled.label`
    font-size: 1.7em;
    margin-right: 10px;
    padding: 5px;
    width: 40%;
    `;

export const Input = styled.input`
    font-size: 1.7em;
    border: 1px solid transparent;
    border-radius: 5px;
    padding: 5px;
    width: 60%;

`;
